import React, { useMemo, useState } from 'react';
import {
  Input,
  Modal,
  SearchInput,
  Select, dispatchAppToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { ToolsEquipmentDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { createAccountSearchConfig, formatAccountDisplay } from '../../../components/search';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { selectPlaceholderClass } from '../../../utils/selectField';
import {
  CatalogFormFooter,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogListGrid,
  CatalogListMasterToolbarSection,
  CatalogListMasterListFooter,
  CatalogFormHistorySlot,
} from '../../../components/catalog';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { toCreateToolsEquipmentPayload, toUpdateToolsEquipmentPayload } from './ccdcPayload';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ccdc';
const CATALOG_KIND = 'tools-equipment';

type FormErrors = Partial<
  Record<'code' | 'name' | 'unit' | 'allocationMonths' | 'accountCode' | 'allocationAccountCode', string>
>;

const CcdcPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<ToolsEquipmentDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<ToolsEquipmentDto | null>(null);
  const initFormName = modalOpen && editing ? 'edit-tools-equipment' : 'create-tools-equipment';
  const { unitOptions } = useVoucherInitData(initFormName);
  const [form, setForm] = useState<Partial<ToolsEquipmentDto>>({ isActive: true, allocationMonths: 12 });
  const [accountName, setAccountName] = useState('');
  const [allocationAccountName, setAllocationAccountName] = useState('');
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService
        .getToolsEquipment({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: err?.message ?? 'Lỗi tải CCDC', type: 'error' });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã CCDC';
    if (!form.name?.trim()) next.name = 'Nhập tên CCDC';
    if (!form.unit?.trim()) next.unit = 'Chọn đơn vị tính';
    const months = form.allocationMonths;
    if (months == null || months < 1 || months > 120) {
      next.allocationMonths = 'Nhập số tháng phân bổ (1–120)';
    }
    if (!form.accountCode?.trim()) next.accountCode = 'Chọn TK hạch toán CCDC';
    if (!form.allocationAccountCode?.trim()) next.allocationAccountCode = 'Chọn TK phân bổ chi phí';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ isActive: true, allocationMonths: 12 });
    setAccountName('');
    setAllocationAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: ToolsEquipmentDto) => {
    setViewOnlyShared(isSharedCatalogReadOnly(row));
    setEditing(row);
    setForm({ ...row });
    setAccountName('');
    setAllocationAccountName('');
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateToolsEquipment(editing.id, toUpdateToolsEquipmentPayload(form));
      } else {
        await masterService.createToolsEquipment(toCreateToolsEquipmentPayload(form));
      }
      markClean();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật CCDC thành công' : 'Tạo CCDC thành công',
        type: 'success',
      });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateToolsEquipment(id, toUpdateToolsEquipmentPayload({ ...row, isActive: false }));
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} CCDC`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteToolsEquipment(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} CCDC`, type: 'success' });
    }
    refresh();
  };

  const filterBar = (
    <>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <Input
          placeholder="Tìm mã, tên..."
          value={searchDraft}
          onChange={e => setSearchDraft(e.target.value)}
          onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
        />
      </div>
      <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} />
    </>
  );

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-toolbox" /> Danh mục CCDC</h1>
        </div>
      </div>

      <CatalogListMasterToolbarSection
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={items}
        onAdd={openAdd}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
      />

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách CCDC"
        showTableLoading={showTableLoading}
        filters={filterBar}
        footer={
          <CatalogListMasterListFooter
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            shared={shared}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        }
      >
        {items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy CCDC phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <CatalogListGrid
            testIdPrefix={TEST_ID}
            rows={items}
            page={page}
            pageSize={pageSize}
            selection={selection}
            getRowId={r => r.id}
            headerCells={(
              <>
                <th>Mã</th>
                <th>Tên</th>
                <CatalogCompanyTh />
                <th>ĐVT</th>
                <th>Số tháng PB</th>
                <th>TK CCDC</th>
                <th>TK phân bổ</th>
                <th>Trạng thái</th>
              </>
            )}
            renderRow={r => (
              <>
                <td><code>{r.code}</code></td>
                <td>{r.name}</td>
                <CatalogCompanyTd label={r.companyName} />
                <td>{r.unit || '—'}</td>
                <td>{r.allocationMonths ?? '—'}</td>
                <td>{r.accountCode || '—'}</td>
                <td>{r.allocationAccountCode || '—'}</td>
                <td>
                  <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                    {r.isActive ? 'Dùng' : 'Ngưng'}
                  </span>
                </td>
              </>
            )}
          />
        )}
      </CatalogListShell>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem CCDC dùng chung' : editing ? 'Sửa CCDC' : 'Thêm CCDC'}
        size="md"
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã CCDC *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên CCDC *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-unit`}>
              <label className={styles.label}>Đơn vị tính *</label>
              <Select
                value={form.unit ?? ''}
                required
                disabled={viewOnlyShared}
                placeholder="— Chọn ĐVT —"
                error={errors.unit}
                className={selectPlaceholderClass(form.unit)}
                onChange={e => {
                  markDirty();
                  clearFieldError('unit');
                  setForm(f => ({ ...f, unit: normalizeCode(e.target.value) }));
                }}
                options={unitOptions}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-allocationMonths`}>
              <label className={styles.label}>Số tháng phân bổ *</label>
              <Input
                type="number"
                min={1}
                max={120}
                value={form.allocationMonths ?? ''}
                disabled={viewOnlyShared}
                error={errors.allocationMonths}
                onChange={e => {
                  markDirty();
                  clearFieldError('allocationMonths');
                  setForm(f => ({
                    ...f,
                    allocationMonths: e.target.value ? Number(e.target.value) : undefined,
                  }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-accountCode`}>
              <label className={styles.label}>TK hạch toán CCDC *</label>
              <SearchInput
                config={accountSearchConfig}
                value={form.accountCode ?? ''}
                primaryDisplay={formatAccountDisplay(form.accountCode ?? '', accountName)}
                error={errors.accountCode}
                onChange={a => {
                  markDirty();
                  clearFieldError('accountCode');
                  setForm(f => ({ ...f, accountCode: normalizeCode(a.code) }));
                  setAccountName(a.name);
                }}
                onClear={() => {
                  markDirty();
                  setForm(f => ({ ...f, accountCode: undefined }));
                  setAccountName('');
                  setErrors(prev => ({ ...prev, accountCode: 'Chọn TK hạch toán CCDC' }));
                }}
                showLabel={false}
                showSecondaryInput={false}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-allocationAccountCode`}>
              <label className={styles.label}>TK phân bổ chi phí *</label>
              <SearchInput
                config={accountSearchConfig}
                value={form.allocationAccountCode ?? ''}
                primaryDisplay={formatAccountDisplay(form.allocationAccountCode ?? '', allocationAccountName)}
                error={errors.allocationAccountCode}
                onChange={a => {
                  markDirty();
                  clearFieldError('allocationAccountCode');
                  setForm(f => ({ ...f, allocationAccountCode: normalizeCode(a.code) }));
                  setAllocationAccountName(a.name);
                }}
                onClear={() => {
                  markDirty();
                  setForm(f => ({ ...f, allocationAccountCode: undefined }));
                  setAllocationAccountName('');
                  setErrors(prev => ({ ...prev, allocationAccountCode: 'Chọn TK phân bổ chi phí' }));
                }}
                showLabel={false}
                showSecondaryInput={false}
              />
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{
              name: form.name,
              unit: form.unit,
              allocationMonths: form.allocationMonths,
              accountCode: form.accountCode,
              allocationAccountCode: form.allocationAccountCode,
              isActive: form.isActive,
            }}
            {...sharedForm}
          />
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
            historySlot={
              <CatalogFormHistorySlot
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                editing={editing ? { id: editing.id, code: editing.code } : null}
              />
            }
            saveDisabled={viewOnlyShared}
          />
        </div>
      </Modal>

      <LeaveConfirmModal {...leaveConfirmModalProps} />
    </div>
  );
};

export default CcdcPage;
